+    #[test]
+    fn execute_selected_returns_noop_on_out_of_bounds() {
+        let items = vec![item(PaletteAction::ToggleTheme, "Theme", "Toggle")];
+        let mut state = PaletteState::new(items);
+        state.selected = 5; // out of bounds
