+    #[test]
+    fn execute_selected_dispatches_first_item() {
+        let items = vec![
+            item(PaletteAction::ToggleTheme, "Theme", "Toggle"),
+            item(PaletteAction::ReloadIndex, "Reload", "Refresh"),
